import { useEffect, useState } from "react";

export default function Dashboard() {
  const [incidents, setIncidents] = useState([]);
  const [statusFilter, setStatusFilter] = useState("ALL");
  const [severityFilter, setSeverityFilter] = useState("ALL");

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    const res = await fetch("http://localhost:8000/incidents");
    const data = await res.json();
    setIncidents(data);
  };

  const filtered = incidents.filter(i => {
    return (
      (statusFilter === "ALL" || i.status === statusFilter) &&
      (severityFilter === "ALL" || i.severity === severityFilter)
    );
  });

  return (
    <div style={{ background: "#f5f6f8", minHeight: "100vh", padding: "20px" }}>
      
      {/* HEADER */}
      <div style={header}>
        <h2>🔵 IT Incidents Dashboard</h2>
        <button style={createBtn}>+ Create New Incident</button>
      </div>

      {/* FILTERS */}
      <div style={filters}>
        <select onChange={(e) => setSeverityFilter(e.target.value)}>
          <option value="ALL">All Priorities</option>
          <option value="P0">P0</option>
          <option value="P1">P1</option>
        </select>

        <select onChange={(e) => setStatusFilter(e.target.value)}>
          <option value="ALL">All Statuses</option>
          <option value="OPEN">Open</option>
          <option value="CLOSED">Closed</option>
        </select>
      </div>

      {/* CARDS */}
      <div style={grid}>
        {filtered.map((i) => (
          <div key={i.id} style={card}>
            
            <h3>{i.component_id}</h3>

            <p style={{ color: "#666" }}>
              Incident #{i.id}
            </p>

            <div style={badgeRow}>
              <span style={severityBadge(i.severity)}>
                {i.severity}
              </span>

              <span style={statusBadge(i.status)}>
                {i.status}
              </span>
            </div>

            <p style={{ marginTop: "10px" }}>
              Signals: {i.signal_count}
            </p>

          </div>
        ))}
      </div>
    </div>
  );
}

//
// 🎨 STYLES
//

const header = {
  display: "flex",
  justifyContent: "space-between",
  alignItems: "center",
  background: "#fff",
  padding: "15px",
  borderRadius: "8px",
  marginBottom: "15px",
  boxShadow: "0 2px 6px rgba(0,0,0,0.05)"
};

const createBtn = {
  background: "#2f6fed",
  color: "#fff",
  padding: "8px 12px",
  border: "none",
  borderRadius: "6px",
  cursor: "pointer"
};

const filters = {
  display: "flex",
  gap: "10px",
  marginBottom: "20px"
};

const grid = {
  display: "grid",
  gridTemplateColumns: "repeat(auto-fit, minmax(280px, 1fr))",
  gap: "15px"
};

const card = {
  background: "#fff",
  padding: "15px",
  borderRadius: "10px",
  boxShadow: "0 2px 6px rgba(0,0,0,0.08)"
};

const badgeRow = {
  display: "flex",
  justifyContent: "space-between",
  marginTop: "10px"
};

const severityBadge = (sev) => ({
  padding: "4px 10px",
  borderRadius: "12px",
  background: sev === "P0" ? "#ffd6d6" : "#fff3cd",
  color: sev === "P0" ? "red" : "#856404",
  fontSize: "12px"
});

const statusBadge = (status) => ({
  padding: "4px 10px",
  borderRadius: "12px",
  background: status === "OPEN" ? "#e0ecff" : "#d4edda",
  color: status === "OPEN" ? "#0056b3" : "green",
  fontSize: "12px"
});
